import re

def count_politicians(articles, politician_names):
    # Create a set of lowercase politician names for case-insensitive matching
    lowercase_politician_names = {name.lower() for name in politician_names}

    # Initialize a dictionary to hold counts
    counts = {}

    # Process each article
    for article in articles:
        # Extract all names from the article (case-insensitive and ignoring punctuation)
        names = re.findall(r'\b\w+\b', article)
        for name in names:
            # Convert to lowercase and check if it's a politician's name
            lower_name = name.lower()
            if lower_name in lowercase_politician_names:
                # Increment the count for this politician
                counts[lower_name] = counts.get(lower_name, 0) + 1

    return counts
